// Process AI analysis results and generate strategic recommendations
const brandConfig = $('Configure Brand Analysis').first();
const performanceAnalysis = $('Analyze Content Performance').first();
const trendAnalysis = $('Identify Content Trends').first();
const seoAnalysis = $('Optimize SEO Strategy').first();

// Extract AI responses
const performanceInsights = performanceAnalysis.choices?.[0]?.message?.content || '';
const trendInsights = trendAnalysis.content?.[0]?.text || '';
const seoInsights = seoAnalysis.choices?.[0]?.message?.content || '';

// Parse and structure insights
function parseInsights(text, category) {
  const lines = text.split('\n').filter(line => line.trim());
  const insights = [];

  lines.forEach(line => {
    if (line.includes('•') || line.includes('-') || line.includes('1.') || line.includes('2.')) {
      insights.push({
        category,
        insight: line.replace(/^[•\-\d\.\s]+/, '').trim(),
        priority: line.toLowerCase().includes('urgent') || line.toLowerCase().includes('immediate') ? 'high' : 'medium'
      });
    }
  });

  return insights;
}

const allInsights = [
  ...parseInsights(performanceInsights, 'performance'),
  ...parseInsights(trendInsights, 'trends'),
  ...parseInsights(seoInsights, 'seo')
];

// Generate content calendar recommendations
function generateContentCalendar(brand, insights, brandConfig) {
  const calendar = {
    weekly_themes: [],
    daily_content_types: {},
    seasonal_opportunities: [],
    cross_platform_strategy: {}
  };

  // Weekly themes based on content pillars
  brandConfig.content_pillars.forEach((pillar, index) => {
    calendar.weekly_themes.push({
      week: index + 1,
      theme: pillar,
      focus: `${pillar} content with emphasis on engagement and value delivery`,
      content_types: brandConfig.content_types.slice(0, 2)
    });
  });

  // Daily content distribution
  brandConfig.platforms.forEach(platform => {
    const frequency = brandConfig.posting_frequency[platform] || 1;
    calendar.daily_content_types[platform] = {
      posts_per_week: frequency,
      optimal_times: getOptimalPostingTimes(platform, brand),
      content_mix: getContentMix(platform, brandConfig.content_types)
    };
  });

  // Seasonal opportunities (next 3 months)
  calendar.seasonal_opportunities = getSeasonalOpportunities(brand, brandConfig.target_audience);

  return calendar;
}

function getOptimalPostingTimes(platform, brand) {
  const timingMap = {
    youtube: ['Tuesday 2PM', 'Thursday 3PM', 'Saturday 10AM'],
    instagram: ['Monday 11AM', 'Wednesday 2PM', 'Friday 5PM'],
    tiktok: ['Tuesday 6AM', 'Thursday 7PM', 'Sunday 9AM'],
    facebook: ['Wednesday 1PM', 'Friday 3PM', 'Sunday 2PM'],
    pinterest: ['Saturday 8PM', 'Sunday 9PM', 'Tuesday 8PM'],
    linkedin: ['Tuesday 10AM', 'Wednesday 12PM', 'Thursday 2PM'],
    twitter: ['Monday 9AM', 'Wednesday 3PM', 'Friday 5PM'],
    blog: ['Tuesday 10AM', 'Thursday 2PM']
  };

  return timingMap[platform] || ['Monday 12PM', 'Wednesday 3PM', 'Friday 5PM'];
}

function getContentMix(platform, contentTypes) {
  const platformMix = {
    youtube: { video: 0.8, shorts: 0.2 },
    instagram: { posts: 0.4, stories: 0.3, reels: 0.3 },
    tiktok: { videos: 1.0 },
    facebook: { posts: 0.6, videos: 0.4 },
    pinterest: { pins: 0.8, idea_pins: 0.2 },
    linkedin: { posts: 0.7, articles: 0.3 },
    twitter: { tweets: 0.8, threads: 0.2 },
    blog: { articles: 1.0 }
  };

  return platformMix[platform] || { posts: 1.0 };
}

function getSeasonalOpportunities(brand, audience) {
  const currentMonth = new Date().getMonth();
  const opportunities = [];

  // Generate next 3 months of opportunities
  for (let i = 0; i < 3; i++) {
    const month = (currentMonth + i) % 12;
    const monthName = new Date(2024, month).toLocaleString('default', { month: 'long' });

    const seasonalContent = {
      travel: {
        0: 'New Year travel resolutions', 1: 'Valentine\'s romantic getaways', 2: 'Spring break destinations',
        3: 'Easter travel traditions', 4: 'Mother\'s Day trips', 5: 'Summer vacation planning',
        6: 'Independence Day celebrations', 7: 'Back-to-school family trips', 8: 'Fall foliage tours',
        9: 'Halloween destinations', 10: 'Thanksgiving travel tips', 11: 'Christmas markets'
      },
      faith: {
        0: 'New Year spiritual goals', 1: 'Love and relationships', 2: 'Lenten reflections',
        3: 'Easter celebrations', 4: 'Mother\'s Day blessings', 5: 'Summer spiritual retreats',
        6: 'Freedom in faith', 7: 'Back-to-school prayers', 8: 'Gratitude practices',
        9: 'All Saints Day', 10: 'Thanksgiving devotions', 11: 'Christmas preparations'
      },
      anime: {
        0: 'New Year anime resolutions', 1: 'Romance anime recommendations', 2: 'Spring anime season',
        3: 'Easter anime specials', 4: 'Mother figures in anime', 5: 'Summer anime festivals',
        6: 'Patriotic anime themes', 7: 'School anime series', 8: 'Fall anime premieres',
        9: 'Halloween anime episodes', 10: 'Thanksgiving anime moments', 11: 'Christmas anime specials'
      }
    };

    const brandCategory = brand.includes('traveler') ? 'travel' : 
                         brand.includes('vessel') ? 'faith' : 
                         brand.includes('ani') ? 'anime' : 'travel';

    opportunities.push({
      month: monthName,
      theme: seasonalContent[brandCategory][month],
      content_focus: `${monthName} ${brandCategory} content opportunities`,
      estimated_engagement_boost: '15-30%'
    });
  }

  return opportunities;
}

// Generate strategic recommendations
const contentCalendar = generateContentCalendar(brandConfig.brand, allInsights, brandConfig.brandConfig);

// Calculate strategy scores
const strategyScore = {
  content_diversity: Math.min(100, (brandConfig.brandConfig.content_types.length / 6) * 100),
  platform_coverage: Math.min(100, (brandConfig.brandConfig.platforms.length / 8) * 100),
  posting_frequency: Math.min(100, Object.values(brandConfig.brandConfig.posting_frequency).reduce((a, b) => a + b, 0) / 10 * 100),
  audience_alignment: 85 // Based on content pillar alignment
};

const overallScore = Object.values(strategyScore).reduce((a, b) => a + b, 0) / 4;

// Priority action items
const actionItems = allInsights
  .filter(insight => insight.priority === 'high')
  .slice(0, 5)
  .map((insight, index) => ({
    priority: index + 1,
    category: insight.category,
    action: insight.insight,
    estimated_impact: 'medium_to_high',
    timeframe: '1-2 weeks'
  }));

return {
  brand: brandConfig.brand,
  strategy_analysis: {
    performance_insights: performanceInsights.substring(0, 500),
    trend_insights: trendInsights.substring(0, 500),
    seo_insights: seoInsights.substring(0, 500)
  },
  content_calendar: contentCalendar,
  strategy_score: {
    individual_scores: strategyScore,
    overall_score: overallScore,
    grade: overallScore >= 90 ? 'A' : overallScore >= 80 ? 'B' : overallScore >= 70 ? 'C' : 'D'
  },
  action_items: actionItems,
  insights_summary: {
    total_insights: allInsights.length,
    high_priority: allInsights.filter(i => i.priority === 'high').length,
    categories: {
      performance: allInsights.filter(i => i.category === 'performance').length,
      trends: allInsights.filter(i => i.category === 'trends').length,
      seo: allInsights.filter(i => i.category === 'seo').length
    }
  },
  analysis_timestamp: brandConfig.analysisTimestamp
};
